module top_module(
  input [n-1:0] addr,
  output [m-1:0] data
);parameter n = 3; // number of address signals
parameter m = 8; // number of data signals
parameter d = 8; // number of data words
parameter w = 8; // number of bits per data word

reg [w-1:0] mem [0:d-1];

initial begin
  // Initialize the ROM with data words
  mem[0] = 8'b00000000;
  mem[1] = 8'b00000001;
  mem[2] = 8'b00000010;
  mem[3] = 8'b00000011;
  mem[4] = 8'b00000100;
  mem[5] = 8'b00000101;
  mem[6] = 8'b00000110;
  mem[7] = 8'b00000111;
end

assign data = mem[addr];

endmodule
